// 1-2 random posts per day, hours 10-20
const today = new Date();
const seed = today.getFullYear() * 10000 + (today.getMonth() + 1) * 100 + today.getDate();

function seededRandom(s) {
  const x = Math.sin(s) * 10000;
  return x - Math.floor(x);
}

// Random number of posts: 1 or 2
const numPosts = 1 + Math.floor(seededRandom(seed * 13) * 2);

// Generate unique hours between 10-20
const hours = new Set();
let i = 0;
while (hours.size < numPosts && i < 100) {
  const hour = 10 + Math.floor(seededRandom(seed + i + 500) * 11);
  hours.add(hour);
  i++;
}

const currentHour = today.getHours();
const scheduledHours = Array.from(hours).sort((a, b) => a - b);

console.log(`Today: ${numPosts} social posts at hours: ${scheduledHours.join(', ')}`);
console.log(`Current hour: ${currentHour}`);

if (scheduledHours.includes(currentHour)) {
  const waitMinutes = Math.floor(seededRandom(seed + currentHour * 200) * 55);
  console.log(`Active! Waiting ${waitMinutes} minutes before posting`);

  return [{
    json: {
      scheduledHours,
      currentHour,
      waitMinutes,
      numPostsToday: numPosts,
      expectedPostTime: `${currentHour}:${waitMinutes.toString().padStart(2, '0')}`,
      shouldRun: true
    }
  }];
}

console.log('Skipping - not a scheduled hour');
return [];

// Get all available media from table
const allMedia = $input.all();

// Filter: source_folder === 'socialmedia', not yet posted, only images
const available = allMedia.filter(item => {
  const sf = item.json.source_folder;
  const posted = item.json.added_to_social_media;
  const filePath = item.json.file_path || '';
  const ext = filePath.toLowerCase().slice(filePath.lastIndexOf('.'));
  const isVideo = ['.mp4', '.mov', '.avi', '.mkv', '.webm'].includes(ext);

  return sf === 'socialmedia' && posted === false && !isVideo;
});

if (available.length === 0) {
  throw new Error('No available social media content found (all already posted or none in socialmedia folder)');
}

// Select random file
const randomIndex = Math.floor(Math.random() * available.length);
const selected = available[randomIndex];

const filePath = selected.json.file_path;
const fileName = filePath.split('/').pop();

// Use description_social, fallback to generic
let caption = selected.json.description_social;
if (!caption || caption.trim().length < 5) {
  caption = '';
}

return [{
  json: {
    id: selected.json.id,
    selectedPath: selected.json.file_path,
    fileName: fileName,
    description_social: caption,
    source_folder: selected.json.source_folder,
    totalAvailable: available.length,
    selectedIndex: randomIndex
  }
}];

const selectedData = $('Select Social Content').first().json;
const sharedLinkData = $input.first().json;

// Get shared link URL - convert to direct download link
let imageUrl = sharedLinkData.url || sharedLinkData.shared_link || '';
// Convert Dropbox share link to direct download
if (imageUrl.includes('dropbox.com')) {
  imageUrl = imageUrl.replace('www.dropbox.com', 'dl.dropboxusercontent.com').replace('?dl=0', '').replace('&dl=0', '');
}

// Use description_social from media_catalog
let caption = selectedData.description_social;

// Fallback SFW captions if empty
if (!caption || caption.trim().length < 5) {
  const fallbackCaptions = [
    'New day, new vibes! How are you doing today? #mood #vibes',
    'Just me being me. Hope your day is as beautiful as you are! #selfie #beauty',
    'Good things take time. Enjoying every moment! #lifestyle #happy',
    'Smile more, worry less. Life is too short! #positivity #smile',
    'Another beautiful day, another reason to be grateful! #blessed #grateful'
  ];
  caption = fallbackCaptions[Math.floor(Math.random() * fallbackCaptions.length)];
}

return [{
  json: {
    image_url: imageUrl,
    caption: caption,
    file_name: selectedData.fileName,
    file_path: selectedData.selectedPath,
    media_id: selectedData.id,
    total_remaining: selectedData.totalAvailable - 1
  }
}];
